-- Insert 50 agility / shiftiness exercises
INSERT INTO coaching.exercise (
  facility_id, name, slug, description, sport_id, skill_level, age_min,
  default_sets, default_reps, default_work_seconds, default_rest_seconds, est_seconds_per_set,
  is_published, visibility,
  card_summary, coach_language, athlete_language,
  movement_family, primary_phase_key, phase_subrole, primary_order_slot,
  movement_requirements, coaching_execution
)
SELECT
  f.id,
  d.name, d.slug, d.description,
  (SELECT id FROM coaching.sport WHERE key = 'fitness'),
  d.skill::public.skill_level,
  d.age_min,
  d.sets, d.reps, d.work, d.rest, d.est,
  TRUE, 'facility',
  d.summary, d.coach_lang, d.athlete_lang,
  d.family, d.phase_key, d.subrole, d.slot,
  d.req::jsonb, d.exec::jsonb
FROM (VALUES
  ('Line Pogo Hops', 'line-pogo-hops', 'Line Pogo Hops is a elastic stiffness and foot reactivity drill. The athlete uses clear start, plant, stop, or exit targets to rehearse two-foot vertical stiffness before cuts, emphasizing low hips, clean foot placement, aligned braking, and an immediate reacceleration or stable stick depending on the drill intent.', 'BEGINNER', 8, 2, 20, 20, 20, 40, 'Line Pogo Hops targets two-foot vertical stiffness before cuts for athletes who need fast stops, sharp cuts, and explosive reacceleration. It was selected for football receivers, soccer players, lacrosse players, and other field-sport athletes who need dynamic shiftiness without sacrificing joint control.', 'Primary subrole: potentiate_bridge. Use this card for elastic stiffness and foot reactivity. Coach the entry, plant, and exit as separate qualities before blending them into faster sport-like reps.', 'Brake clean, own the edge, then explode out.', 'Elastic Foot & Ankle Prep', 'prepare_and_access', 'potentiate_bridge', 'elastic_prep', '{"primary_joint_actions":["ankle_stiffness","knee_flexion_extension_control","hip_flexion_extension","hip_abduction_adduction_control"],"primary_tissues":["foot_intrinsics","calf_achilles_complex","quadriceps","hamstrings","gluteals","adductors"],"primary_motor_control_demands":["center_of_mass_control","edge_control","trunk_pelvis_alignment","braking_angle_ownership"],"postural_shape":"athletic stance with ribs stacked over pelvis, hips loaded, eyes up, and shin angle matched to intended direction","breathing_demand":"natural exhale through effort; no breath-holding during braking or cutting","balance_demand":"low dynamic balance with elastic rhythm","coordination_demand":"high timing demand: foot strike, hip load, trunk orientation, visual cue, and reacceleration must stay connected","impact_level":1}'::jsonb, '{"movement_description":"Line Pogo Hops develops two-foot vertical stiffness before cuts for field and court athletes who need abrupt stops, quick redirection, and explosive reacceleration while preserving posture and joint alignment.","setup":["Use a flat, dry surface with enough clear space for the prescribed approach and exit.","Mark start, plant, stop, or exit targets with cones when needed.","Athlete starts tall enough to see the field but low enough to load hips and push the ground."],"execution_steps":["Bounce or hop in a small amplitude while keeping contacts quick and quiet.","Keep knees soft, heels barely kissing or hovering based on athlete level.","Maintain rhythm for the prescribed contacts, then stop before stiffness becomes sloppy."],"coach_cues":["Quick and quiet off the floor.","Tall posture, springy ankles.","Stop while it still feels crisp."],"common_faults":["Contacts getting loud or slow.","Knees locking out.","Shoulders bouncing excessively.","Athlete chasing fatigue instead of rhythm."]}'::jsonb),
  ('Lateral Line Pogo Hops', 'lateral-line-pogo-hops', 'Lateral Line Pogo Hops is a elastic stiffness and foot reactivity drill. The athlete uses clear start, plant, stop, or exit targets to rehearse side-to-side ankle stiffness, emphasizing low hips, clean foot placement, aligned braking, and an immediate reacceleration or stable stick depending on the drill intent.', 'BEGINNER', 8, 2, 20, 20, 20, 40, 'Lateral Line Pogo Hops targets side-to-side ankle stiffness for athletes who need fast stops, sharp cuts, and explosive reacceleration. It was selected for football receivers, soccer players, lacrosse players, and other field-sport athletes who need dynamic shiftiness without sacrificing joint control.', 'Primary subrole: potentiate_bridge. Use this card for elastic stiffness and foot reactivity. Coach the entry, plant, and exit as separate qualities before blending them into faster sport-like reps.', 'Brake clean, own the edge, then explode out.', 'Elastic Foot & Ankle Prep', 'prepare_and_access', 'potentiate_bridge', 'lateral_elastic_prep', '{"primary_joint_actions":["ankle_stiffness","knee_flexion_extension_control","hip_flexion_extension","hip_abduction_adduction_control"],"primary_tissues":["foot_intrinsics","calf_achilles_complex","quadriceps","hamstrings","gluteals","adductors"],"primary_motor_control_demands":["center_of_mass_control","edge_control","trunk_pelvis_alignment","braking_angle_ownership"],"postural_shape":"athletic stance with ribs stacked over pelvis, hips loaded, eyes up, and shin angle matched to intended direction","breathing_demand":"natural exhale through effort; no breath-holding during braking or cutting","balance_demand":"low dynamic balance with elastic rhythm","coordination_demand":"high timing demand: foot strike, hip load, trunk orientation, visual cue, and reacceleration must stay connected","impact_level":1}'::jsonb, '{"movement_description":"Lateral Line Pogo Hops develops side-to-side ankle stiffness for field and court athletes who need abrupt stops, quick redirection, and explosive reacceleration while preserving posture and joint alignment.","setup":["Use a flat, dry surface with enough clear space for the prescribed approach and exit.","Mark start, plant, stop, or exit targets with cones when needed.","Athlete starts tall enough to see the field but low enough to load hips and push the ground."],"execution_steps":["Bounce or hop in a small amplitude while keeping contacts quick and quiet.","Keep knees soft, heels barely kissing or hovering based on athlete level.","Maintain rhythm for the prescribed contacts, then stop before stiffness becomes sloppy."],"coach_cues":["Quick and quiet off the floor.","Tall posture, springy ankles.","Stop while it still feels crisp."],"common_faults":["Contacts getting loud or slow.","Knees locking out.","Shoulders bouncing excessively.","Athlete chasing fatigue instead of rhythm."]}'::jsonb),
  ('Forward-Back Line Hops', 'forward-back-line-hops', 'Forward-Back Line Hops is a elastic stiffness and foot reactivity drill. The athlete uses clear start, plant, stop, or exit targets to rehearse brake-and-pop rhythm in the sagittal plane, emphasizing low hips, clean foot placement, aligned braking, and an immediate reacceleration or stable stick depending on the drill intent.', 'BEGINNER', 8, 2, 20, 20, 20, 40, 'Forward-Back Line Hops targets brake-and-pop rhythm in the sagittal plane for athletes who need fast stops, sharp cuts, and explosive reacceleration. It was selected for football receivers, soccer players, lacrosse players, and other field-sport athletes who need dynamic shiftiness without sacrificing joint control.', 'Primary subrole: potentiate_bridge. Use this card for elastic stiffness and foot reactivity. Coach the entry, plant, and exit as separate qualities before blending them into faster sport-like reps.', 'Brake clean, own the edge, then explode out.', 'Elastic Foot & Ankle Prep', 'prepare_and_access', 'potentiate_bridge', 'sagittal_elastic_prep', '{"primary_joint_actions":["ankle_stiffness","knee_flexion_extension_control","hip_flexion_extension","hip_abduction_adduction_control"],"primary_tissues":["foot_intrinsics","calf_achilles_complex","quadriceps","hamstrings","gluteals","adductors"],"primary_motor_control_demands":["center_of_mass_control","edge_control","trunk_pelvis_alignment","braking_angle_ownership"],"postural_shape":"athletic stance with ribs stacked over pelvis, hips loaded, eyes up, and shin angle matched to intended direction","breathing_demand":"natural exhale through effort; no breath-holding during braking or cutting","balance_demand":"low dynamic balance with elastic rhythm","coordination_demand":"high timing demand: foot strike, hip load, trunk orientation, visual cue, and reacceleration must stay connected","impact_level":1}'::jsonb, '{"movement_description":"Forward-Back Line Hops develops brake-and-pop rhythm in the sagittal plane for field and court athletes who need abrupt stops, quick redirection, and explosive reacceleration while preserving posture and joint alignment.","setup":["Use a flat, dry surface with enough clear space for the prescribed approach and exit.","Mark start, plant, stop, or exit targets with cones when needed.","Athlete starts tall enough to see the field but low enough to load hips and push the ground."],"execution_steps":["Bounce or hop in a small amplitude while keeping contacts quick and quiet.","Keep knees soft, heels barely kissing or hovering based on athlete level.","Maintain rhythm for the prescribed contacts, then stop before stiffness becomes sloppy."],"coach_cues":["Quick and quiet off the floor.","Tall posture, springy ankles.","Stop while it still feels crisp."],"common_faults":["Contacts getting loud or slow.","Knees locking out.","Shoulders bouncing excessively.","Athlete chasing fatigue instead of rhythm."]}'::jsonb),
  ('Single-Leg Line Hop and Stick', 'single-leg-line-hop-and-stick', 'Single-Leg Line Hop and Stick is a elastic stiffness and foot reactivity drill. The athlete uses clear start, plant, stop, or exit targets to rehearse single-leg stiffness plus stick ownership, emphasizing low hips, clean foot placement, aligned braking, and an immediate reacceleration or stable stick depending on the drill intent.', 'BEGINNER', 8, 3, 4, 20, 40, 60, 'Single-Leg Line Hop and Stick targets single-leg stiffness plus stick ownership for athletes who need fast stops, sharp cuts, and explosive reacceleration. It was selected for football receivers, soccer players, lacrosse players, and other field-sport athletes who need dynamic shiftiness without sacrificing joint control.', 'Primary subrole: balance_coordination_rhythm. Use this card for elastic stiffness and foot reactivity. Coach the entry, plant, and exit as separate qualities before blending them into faster sport-like reps.', 'Brake clean, own the edge, then explode out.', 'Single-Leg Elastic Control', 'movement_intelligence', 'balance_coordination_rhythm', 'single_leg_hop_rhythm', '{"primary_joint_actions":["ankle_stiffness","knee_flexion_extension_control","hip_flexion_extension","hip_abduction_adduction_control"],"primary_tissues":["foot_intrinsics","calf_achilles_complex","quadriceps","hamstrings","gluteals","adductors"],"primary_motor_control_demands":["center_of_mass_control","edge_control","trunk_pelvis_alignment","braking_angle_ownership"],"postural_shape":"athletic stance with ribs stacked over pelvis, hips loaded, eyes up, and shin angle matched to intended direction","breathing_demand":"natural exhale through effort; no breath-holding during braking or cutting","balance_demand":"dynamic single-leg and split-stance balance","coordination_demand":"high timing demand: foot strike, hip load, trunk orientation, visual cue, and reacceleration must stay connected","impact_level":2}'::jsonb, '{"movement_description":"Single-Leg Line Hop and Stick develops single-leg stiffness plus stick ownership for field and court athletes who need abrupt stops, quick redirection, and explosive reacceleration while preserving posture and joint alignment.","setup":["Use a flat, dry surface with enough clear space for the prescribed approach and exit.","Mark start, plant, stop, or exit targets with cones when needed.","Athlete starts tall enough to see the field but low enough to load hips and push the ground."],"execution_steps":["Execute the Single-Leg Line Hop and Stick with the stated focus: single-leg stiffness plus stick ownership.","Enter the rep with quiet feet and an active trunk; do not rush the setup.","Load the hip, knee, and ankle together; keep the foot tripod and knee tracking over the midfoot.","Finish by sticking, braking, or exiting with the first two steps clean and intentional.","Reset fully before the next rep so every attempt is a quality repetition, not conditioning by accident.","Use coach call, opponent movement, or sport implement only after the athlete demonstrates the base rhythm cleanly."],"coach_cues":["Brake before you turn.","Hips low, chest proud, eyes up.","Push the ground away; do not reach for the cone.","Quiet stick, violent exit.","Knee over midfoot; own the inside edge."],"common_faults":["Extra gather steps before the plant.","Knee collapsing inside the foot during the stop or cut.","Torso rotating away from the intended exit.","Plant foot too narrow, too far ahead, or too turned out for the cut angle.","Turning the drill into conditioning volume instead of quality movement."]}'::jsonb),
