  ('Rear-Foot Elevated Split Squat Iso Cut Position', 'rear-foot-elevated-split-squat-iso-cut-position', 'Rear-Foot Elevated Split Squat Iso Cut Position is a strength support for cutting brakes drill. The athlete uses clear start, plant, stop, or exit targets to rehearse isometric single-leg force in cut-like angles, emphasizing low hips, clean foot placement, aligned braking, and an immediate reacceleration or stable stick depending on the drill intent.', 'BEGINNER', 8, 3, NULL, 30, 90, 120, 'Rear-Foot Elevated Split Squat Iso Cut Position targets isometric single-leg force in cut-like angles for athletes who need fast stops, sharp cuts, and explosive reacceleration. It was selected for football receivers, soccer players, lacrosse players, and other field-sport athletes who need dynamic shiftiness without sacrificing joint control.', 'Primary subrole: squat_knee_dominant_strength. Use this card for strength support for cutting brakes. Coach the entry, plant, and exit as separate qualities before blending them into faster sport-like reps.', 'Brake clean, own the edge, then explode out.', 'Single-Leg Strength Capacity', 'capacity', 'squat_knee_dominant_strength', 'rfess_iso_cut_position', '{"primary_joint_actions":["hip_flexion_extension","knee_flexion_extension","ankle_dorsiflexion","trunk_bracing"],"primary_tissues":["quadriceps","gluteals","adductors","calf_achilles_complex"],"primary_motor_control_demands":["cut_position_isometric_ownership","knee_over_midfoot","pelvis_level"],"postural_shape":"athletic stance with ribs stacked over pelvis, hips loaded, eyes up, and shin angle matched to intended direction","breathing_demand":"natural exhale through effort; no breath-holding during braking or cutting","balance_demand":"dynamic single-leg and split-stance balance","coordination_demand":"high timing demand: foot strike, hip load, trunk orientation, visual cue, and reacceleration must stay connected","impact_level":0}'::jsonb, '{"movement_description":"Rear-Foot Elevated Split Squat Iso Cut Position develops isometric single-leg force in cut-like angles for field and court athletes who need abrupt stops, quick redirection, and explosive reacceleration while preserving posture and joint alignment.","setup":["Place rear foot on a low box or bench.","Set front foot far enough forward to create a cut-like shin angle without heel lift.","Hold light dumbbells only if the athlete can maintain knee-over-midfoot alignment."],"execution_steps":["Descend into the target cut-like split squat angle.","Hold with front foot rooted and knee tracking over the middle toes.","Keep pelvis level and torso slightly inclined like a cutting posture.","Stand up smoothly or step out before alignment degrades."],"coach_cues":["Brake before you turn.","Hips low, chest proud, eyes up.","Push the ground away; do not reach for the cone.","Quiet stick, violent exit.","Knee over midfoot; own the inside edge."],"common_faults":["Extra gather steps before the plant.","Knee collapsing inside the foot during the stop or cut.","Torso rotating away from the intended exit.","Plant foot too narrow, too far ahead, or too turned out for the cut angle.","Turning the drill into conditioning volume instead of quality movement."]}'::jsonb),
  ('Short-Lever Copenhagen Plank', 'short-lever-copenhagen-plank', 'Short-Lever Copenhagen Plank is a adductor and trunk resilience drill. The athlete uses clear start, plant, stop, or exit targets to rehearse adductor capacity for lateral cuts and groin resilience, emphasizing low hips, clean foot placement, aligned braking, and an immediate reacceleration or stable stick depending on the drill intent.', 'BEGINNER', 8, 2, NULL, 20, 45, 70, 'Short-Lever Copenhagen Plank targets adductor capacity for lateral cuts and groin resilience for athletes who need fast stops, sharp cuts, and explosive reacceleration. It was selected for football receivers, soccer players, lacrosse players, and other field-sport athletes who need dynamic shiftiness without sacrificing joint control.', 'Primary subrole: trunk_pelvis_anti_movement_control. Use this card for adductor and trunk resilience. Coach the entry, plant, and exit as separate qualities before blending them into faster sport-like reps.', 'Brake clean, own the edge, then explode out.', 'Adductor & Trunk Resilience', 'resilience', 'trunk_pelvis_anti_movement_control', 'copenhagen_adductor_resilience', '{"primary_joint_actions":["hip_adduction_abduction_control","lateral_trunk_flexion_control"],"primary_tissues":["adductors","obliques","gluteus_medius"],"primary_motor_control_demands":["pelvis_stack","anti_lateral_flexion","adductor_tension_control"],"postural_shape":"athletic stance with ribs stacked over pelvis, hips loaded, eyes up, and shin angle matched to intended direction","breathing_demand":"natural exhale through effort; no breath-holding during braking or cutting","balance_demand":"dynamic single-leg and split-stance balance","coordination_demand":"high timing demand: foot strike, hip load, trunk orientation, visual cue, and reacceleration must stay connected","impact_level":0}'::jsonb, '{"movement_description":"Short-Lever Copenhagen Plank develops adductor capacity for lateral cuts and groin resilience for field and court athletes who need abrupt stops, quick redirection, and explosive reacceleration while preserving posture and joint alignment.","setup":["Set a bench or box at knee height or lower.","Place top knee or lower leg on the support and bottom forearm under shoulder.","Stack ribs, pelvis, and shoulders in a straight side-plank line."],"execution_steps":["Lift hips until body forms a straight line.","Press top leg into the bench and gently lift bottom leg or keep it supported as needed.","Hold without rib flare, hip sag, or groin pain.","Lower under control and switch sides."],"coach_cues":["Long line from ear to ankle.","Press the bench away with the top leg.","No hip sag, no groin pinch."],"common_faults":["Hip sagging toward the floor.","Top leg gripping with pain instead of strong tension.","Shoulder shrugging into ear.","Breath held for the full hold."]}'::jsonb),
  ('Repeat COD Shuttle Intervals', 'repeat-cod-shuttle-intervals', 'Repeat COD Shuttle Intervals is a repeatability under fatigue drill. The athlete uses clear start, plant, stop, or exit targets to rehearse maintain posture and braking quality under fatigue, emphasizing low hips, clean foot placement, aligned braking, and an immediate reacceleration or stable stick depending on the drill intent.', 'BEGINNER', 8, 2, 4, 15, 45, 240, 'Repeat COD Shuttle Intervals targets maintain posture and braking quality under fatigue for athletes who need fast stops, sharp cuts, and explosive reacceleration. It was selected for football receivers, soccer players, lacrosse players, and other field-sport athletes who need dynamic shiftiness without sacrificing joint control.', 'Primary subrole: conditioning_intervals. Use this card for repeatability under fatigue. Coach the entry, plant, and exit as separate qualities before blending them into faster sport-like reps.', 'Brake clean, own the edge, then explode out.', 'COD Repeatability', 'sustained_capacity', 'conditioning_intervals', 'repeat_cod_shuttle_intervals', '{"primary_joint_actions":["ankle_stiffness","knee_flexion_extension_control","hip_flexion_extension","hip_abduction_adduction_control"],"primary_tissues":["foot_intrinsics","calf_achilles_complex","quadriceps","hamstrings","gluteals","adductors"],"primary_motor_control_demands":["center_of_mass_control","edge_control","trunk_pelvis_alignment","braking_angle_ownership"],"postural_shape":"athletic stance with ribs stacked over pelvis, hips loaded, eyes up, and shin angle matched to intended direction","breathing_demand":"natural exhale through effort; no breath-holding during braking or cutting","balance_demand":"dynamic single-leg and split-stance balance","coordination_demand":"high timing demand: foot strike, hip load, trunk orientation, visual cue, and reacceleration must stay connected","impact_level":3}'::jsonb, '{"movement_description":"Repeat COD Shuttle Intervals develops maintain posture and braking quality under fatigue for field and court athletes who need abrupt stops, quick redirection, and explosive reacceleration while preserving posture and joint alignment.","setup":["Use a flat, dry surface with enough clear space for the prescribed approach and exit.","Mark start, plant, stop, or exit targets with cones when needed.","Athlete starts tall enough to see the field but low enough to load hips and push the ground."],"execution_steps":["Execute the Repeat COD Shuttle Intervals with the stated focus: maintain posture and braking quality under fatigue.","Enter the rep with quiet feet and an active trunk; do not rush the setup.","Load the hip, knee, and ankle together; keep the foot tripod and knee tracking over the midfoot.","Finish by sticking, braking, or exiting with the first two steps clean and intentional.","Reset fully before the next rep so every attempt is a quality repetition, not conditioning by accident."],"coach_cues":["Brake before you turn.","Hips low, chest proud, eyes up.","Push the ground away; do not reach for the cone.","Quiet stick, violent exit.","Knee over midfoot; own the inside edge."],"common_faults":["Extra gather steps before the plant.","Knee collapsing inside the foot during the stop or cut.","Torso rotating away from the intended exit.","Plant foot too narrow, too far ahead, or too turned out for the cut angle.","Turning the drill into conditioning volume instead of quality movement."]}'::jsonb)
) AS d(name, slug, description, skill, age_min, sets, reps, work, rest, est, summary, coach_lang, athlete_lang, family, phase_key, subrole, slot, req, exec)
CROSS JOIN public.facility f
ON CONFLICT (facility_id, slug) DO NOTHING;

