  ('pro-agility-5-10-5', 'output', 'pro_agility_5_10_5', 5, TRUE, 5, 4, 4, 4, 'high'),
  ('t-drill', 'output', 't_drill_cod', 5, TRUE, 5, 4, 4, 4, 'high'),
  ('l-drill-3-cone', 'output', 'l_drill_3_cone', 5, TRUE, 5, 4, 4, 4, 'high'),
